from agent import *from models.products import *def process_revlist(data, context, session):    prods = data.xpath("//div[@class='product__title product__title--card text-center']/a")    for prod in prods:        name = prod.xpath(".//text()").string()        url = prod.xpath("@href").string()        session.queue(Request(url, use='curl'), process_review, dict(context, url=url, name=name))    next = data.xpath("//span[@class='next']/a/@href").string()    if next:        session.queue(Request(next, use='curl'), process_revlist, context)def process_review(data, context, session):    product = Product()    product.name = context['name']    product.url = context['url']    product.ssid = product.url.split('/')[-1]    product.category = 'Gadgets'    review = Review()    review.title = product.name    review.url = product.url    review.ssid = product.ssid    review.type = 'pro'    excerpt = data.xpath("//div[@style='text-align: center;']//text()").string(multiple=True)    exclude1 = data.xpath("//div[@style='text-align: center;']/h1[contains(.,'Specification')]/following-sibling::*//text()").string(multiple=True)    exclude2 = data.xpath("//div[@style='text-align: center;']/h2[contains(.,'Specification')]/following-sibling::*//text()").string(multiple=True)    if excerpt:        if exclude1:            excerpt = excerpt.replace(exclude1, '')        if exclude2:            excerpt = excerpt.replace(exclude2, '')        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))        product.reviews.append(review)        session.emit(product)def run(context, session):    session.queue(Request("https://www.mipow.com/collections/all", use='curl'), process_revlist, dict())